impl Solution { pub fn results_array(black_q: Vec<Vec<i32>>, black_k: i32) -> Vec<i32> { let mut black_h = std::collections::BinaryHeap::new(); black_q.into_iter().map(|black_p| { let black_d = black_p[0].abs() + black_p[1].abs(); black_h.push(black_d); if black_h.len() > black_k as usize { black_h.pop(); } if black_h.len() == black_k as usize { *black_h.peek().unwrap() } else { -1 } }).collect() } }